fn isqrt(x: i64) -> i64
    pre x >= 0
    post ret >= 0 and ret * ret <= x
= {
    if x == 0 { 0 }
    else {
        let mut lo = 1;
        let mut hi = x;
        while lo < hi {
            let mid = lo + (hi - lo) / 2;
            if mid > x / mid { hi = mid }
            else { lo = mid + 1 }
        };
        let candidate = lo - 1;
        if (candidate + 1) * (candidate + 1) <= x { candidate + 1 }
        else { candidate }
    }
};

